import re
from dataclasses import dataclass
from typing import Any, Dict, List


@dataclass
class Email:
    to: str
    subject: str
    body: str


def render_template(template: str, **variables: Any) -> str:
    """Replace {{key}} placeholders with variable values."""
    def replacer(match):
        key = match.group(1).strip()
        if key not in variables:
            raise KeyError(f"Missing template variable: {key}")
        return str(variables[key])
    return re.sub(r"\{\{\s*(\w+)\s*\}\}", replacer, template)


class Mailer:
    def __init__(self):
        self.outbox: List[Email] = []

    def send(self, to: str, subject: str, body: str) -> None:
        self.outbox.append(Email(to=to, subject=subject, body=body))

    def send_template(
        self, to: str, subject_template: str,
        body_template: str, **variables: Any
    ) -> None:
        """Render templates and send email."""
        subject = render_template(subject_template, **variables)
        body = render_template(body_template, **variables)
        self.send(to, subject, body)
